document.addEventListener("DOMContentLoaded",()=>{document.querySelectorAll("pre code[class]").forEach(e=>{e.className=e.className.replace(/\blang-(\w+)/g,"language-$1")}),"undefined"!=typeof Prism&&Prism.highlightAll(),document.querySelectorAll(".js_sites-gallery__button").forEach(e=>{e.addEventListener("click",e=>e.preventDefault())}),"undefined"!=typeof MicroModal&&MicroModal.init({disableScroll:!0});const e=document.getElementById("top_header");if(e){const l=()=>{e.classList.toggle("smaller",window.scrollY>50)};window.addEventListener("scroll",l,{passive:!0}),l()}});